# Server Script (DocType Event) - Purchase Receipt - on_submit
# Objectif: pousser les dimensions vers les Serial No des lignes reconfigurables
# Source des serials: Serial and Batch Bundle (priorité) puis row.serial_no (fallback)

# cache items to reduce queries
cache = {}

def get_serials_for_row(row):
    # 1) Try to get serials from Serial and Batch Bundle (common fieldnames)
    bundle_name = (
        row.get("serial_and_batch_bundle")
        or row.get("serial_batch_bundle")
        or row.get("serial_and_batch_bundle_id")
        or row.get("serial_batch_bundle_id")
    )

    serials = []

    if bundle_name and frappe.db.exists("Serial and Batch Bundle", bundle_name):
        b = frappe.get_doc("Serial and Batch Bundle", bundle_name)

        # child table name varies; try common ones
        child_rows = b.get("entries") or b.get("items") or b.get("serials") or []

        for r in child_rows:
            sn = (r.get("serial_no") or "").strip()
            if sn:
                serials.append(sn)

    # 2) Fallback: Purchase Receipt Item.serial_no (old style)
    if not serials:
        serials_text = row.serial_no.strip()
        serials = [s.strip() for s in serials_text.split("\n") if s.strip()]

    # Deduplicate keep order
    seen = set()
    out = []
    for s in serials:
        if s not in seen:
            seen.add(s)
            out.append(s)
    return out


for row in doc.items:
    if not row.item_code:
        continue

    if row.item_code not in cache:
        cache[row.item_code] = frappe.db.get_value(
            "Item", row.item_code, ["custom_is_reconfigurable", "has_serial_no"], as_dict=True
        ) or {}

    meta = cache[row.item_code]
    if not (meta.get("custom_is_reconfigurable") or 0):
        continue

    # safety: item must be serialised
    if not (meta.get("has_serial_no") or 0):
        frappe.throw(f"Item {row.item_code} is reconfigurable but has_serial_no is not enabled (row {row.idx}).")

    L = frappe.utils.flt(row.custom_sheet_length_mm)
    W = frappe.utils.flt(row.custom_sheet_width_mm)
    if L <= 0 or W <= 0:
        frappe.throw(f"Missing dimensions for reconfigurable item {row.item_code} (row {row.idx}).")

    serials = get_serials_for_row(row)
    if not serials:
        frappe.throw(
            f"Serial Numbers are required for reconfigurable item {row.item_code} (row {row.idx})."
        )

    for sn_name in serials:
        # Ensure serial exists
        if not frappe.db.exists("Serial No", sn_name):
            frappe.throw(f"Serial No {sn_name} not found (row {row.idx}).")

        # Set all required fields
        frappe.db.set_value("Serial No", sn_name, {
            "custom_dimension_length_mm": L,
            "custom_dimension_width_mm": W,
            "custom_quality_rating": 5,
            "custom_material_status": "Full",
            "custom_root_serial_no": sn_name,
            "custom_parent_serial_no": None,
        }, update_modified=False)

requires_map = {}

for row in doc.items:
